A debounce function limits how often a function can be called by delaying its execution until after a specified wait time has passed since the last invocation.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

// Example: Log search query only after user stops typing for 300ms
const search = debounce((query) => {
  console.log('Searching for:', query);
}, 300);

// Simulate user typing
search('a');        // No immediate log
search('ab');       // Still no log
search('abc');      // Logs "Searching for: abc" after 300ms of no further calls
```
